import{_ as a,o as e,c as i,ag as t}from"./chunks/framework.BZohXCq9.js";const c=JSON.parse('{"title":"Timeshift – nastavení a používání","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/Prikazy/System/Timeshift.md","filePath":"Linux/Prikazy/System/Timeshift.md"}'),n={name:"Linux/Prikazy/System/Timeshift.md"};function p(o,s,l,h,d,r){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="timeshift-–-nastaveni-a-pouzivani" tabindex="-1">Timeshift – nastavení a používání <a class="header-anchor" href="#timeshift-–-nastaveni-a-pouzivani" aria-label="Permalink to &quot;Timeshift – nastavení a používání&quot;">​</a></h1><p>Timeshift je nástroj pro snapshoty systému Linux.</p><p>Umožňuje vrátit systém do předchozího stavu například když:</p><ul><li>se nepovede update</li><li>rozbije se kernel</li><li>systém přestane bootovat</li><li>rozbije se konfigurace</li></ul><p>Timeshift obnovuje <strong>systémové soubory</strong>, ale běžně <strong>neobnovuje /home</strong>.</p><hr><h1 id="spusteni-timeshift" tabindex="-1">Spuštění Timeshift <a class="header-anchor" href="#spusteni-timeshift" aria-label="Permalink to &quot;Spuštění Timeshift&quot;">​</a></h1><p>Otevři terminál:</p><div class="language-Bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> timeshift-gtk</span></span></code></pre></div><p>nebo z menu:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Menu → Administration → Timeshift</span></span></code></pre></div><hr><h1 id="typ-snapshotu" tabindex="-1">Typ snapshotu <a class="header-anchor" href="#typ-snapshotu" aria-label="Permalink to &quot;Typ snapshotu&quot;">​</a></h1><p>Timeshift nabízí dvě možnosti:</p><p><code>RSYNC</code><code>BTRFS</code></p><p>Pro běžný ext4 systém zvol:</p><p><code>RSYNC</code></p><hr><h1 id="vyber-disku" tabindex="-1">Výběr disku <a class="header-anchor" href="#vyber-disku" aria-label="Permalink to &quot;Výběr disku&quot;">​</a></h1><p>Vyber disk, kam se budou ukládat snapshoty.</p><p>Obvykle:</p><p>interní disk</p><p>Pokud máš hodně místa, můžeš použít i externí disk.</p><hr><h1 id="doporucene-nastaveni-snapshotu" tabindex="-1">Doporučené nastavení snapshotů <a class="header-anchor" href="#doporucene-nastaveni-snapshotu" aria-label="Permalink to &quot;Doporučené nastavení snapshotů&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| typ snapshotu | počet |</span></span>
<span class="line"><span>|---|---|</span></span>
<span class="line"><span>Hourly | 0 |</span></span>
<span class="line"><span>Daily | 5 |</span></span>
<span class="line"><span>Weekly | 3 |</span></span>
<span class="line"><span>Monthly | 2 |</span></span>
<span class="line"><span>Boot | 3 |</span></span></code></pre></div><p>To znamená:</p><ul><li>posledních <strong>5 dní</strong></li><li>poslední <strong>3 týdny</strong></li><li>poslední <strong>2 měsíce</strong></li><li>poslední <strong>3 boot snapshoty</strong></li></ul><hr><h1 id="nastaveni-home" tabindex="-1">Nastavení /home <a class="header-anchor" href="#nastaveni-home" aria-label="Permalink to &quot;Nastavení /home&quot;">​</a></h1><p>Timeshift se zeptá, zda zálohovat <code>/home</code>.</p><p>Doporučení:</p><p>NEZAŠKRTÁVAT /home</p><p>Timeshift je určený hlavně pro systémové soubory:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/usr</span></span>
<span class="line"><span>/boot</span></span>
<span class="line"><span>/lib</span></span>
<span class="line"><span>/etc</span></span></code></pre></div><p>Pro osobní data je lepší použít jiný backup.</p><hr><h1 id="rucni-snapshot" tabindex="-1">Ruční snapshot <a class="header-anchor" href="#rucni-snapshot" aria-label="Permalink to &quot;Ruční snapshot&quot;">​</a></h1><p>Před větší změnou můžeš vytvořit snapshot ručně:</p><div class="language-Bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> timeshift</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --comments</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;before system update&quot;</span></span></code></pre></div><p>nebo v GUI tlačítkem:</p><p><code>Create</code></p><hr><h1 id="automaticky-snapshot-pred-upgrade" tabindex="-1">Automatický snapshot před upgrade <a class="header-anchor" href="#automaticky-snapshot-pred-upgrade" aria-label="Permalink to &quot;Automatický snapshot před upgrade&quot;">​</a></h1><p>Můžeš vytvořit alias pro bezpečný upgrade.</p><p>Otevři konfiguraci shellu:</p><div class="language-Bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">nano</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span></code></pre></div><p>Přidej na konec:</p><div class="language-Bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">alias</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> safe-upgrade</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;sudo timeshift --create --comments &quot;before update&quot; &amp;&amp; sudo apt update &amp;&amp; sudo apt upgrade&#39;</span></span></code></pre></div><p>Použití:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">safe-upgrade</span></span></code></pre></div><p>Tím se:</p><ol><li>vytvoří snapshot</li><li>provede update systému</li></ol><hr><h1 id="obnoveni-systemu" tabindex="-1">Obnovení systému <a class="header-anchor" href="#obnoveni-systemu" aria-label="Permalink to &quot;Obnovení systému&quot;">​</a></h1><p>Pokud se systém rozbije:</p><ol><li>nabootuj <strong>Live USB Linux Mint</strong></li><li>otevři terminál</li></ol><div class="language-Bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> timeshift-launcher</span></span></code></pre></div><ol start="3"><li>vyber snapshot</li><li>klikni <strong>Restore</strong></li></ol><p>Po restartu bude systém vrácen do původního stavu.</p><hr><h1 id="doporucena-kombinace-zaloh" tabindex="-1">Doporučená kombinace záloh <a class="header-anchor" href="#doporucena-kombinace-zaloh" aria-label="Permalink to &quot;Doporučená kombinace záloh&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>| nástroj | účel |</span></span>
<span class="line"><span>|---|---|</span></span>
<span class="line"><span>Timeshift | systém |</span></span>
<span class="line"><span>rsync / Deja Dup | osobní soubory |</span></span>
<span class="line"><span>Git | projekty a kód |</span></span></code></pre></div><hr><h1 id="vyhoda-timeshift" tabindex="-1">Výhoda Timeshift <a class="header-anchor" href="#vyhoda-timeshift" aria-label="Permalink to &quot;Výhoda Timeshift&quot;">​</a></h1><p>Bez Timeshiftu může oprava systému trvat desítky minut.</p><p>S Timeshiftem:</p><div class="language-Bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">restore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> snapshot</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">reboot</span></span></code></pre></div><p>Celá oprava obvykle trvá <strong>2–5 minut</strong>.</p>`,69)])])}const k=a(n,[["render",p]]);export{c as __pageData,k as default};
